def classify_intent(query: str) -> str:
    # Simple semantic rule router
    q = query.lower()
    if any(k in q for k in ["pay", "invoice", "card", "billing"]):
        return "billing_agent"
    if any(k in q for k in ["bug", "broken", "error", "crash"]):
        return "tech_agent"
    return "general_agent"

class TriageSupervisor:
    def __init__(self):
        self.workers = {
            "billing": lambda q: f"Billing Worker processed: {q}",
            "support": lambda q: f"Support Worker processed: {q}"
        }

    def route(self, query: str) -> str:
        if "price" in query or "invoice" in query:
            return self.workers["billing"](query)
        else:
            return self.workers["support"](query)

if __name__ == '__main__':
    supervisor = TriageSupervisor()
    print(supervisor.route("Can you check my invoice details?"))
    print(supervisor.route("How do I reset my password?"))
